import { describe, it, expect } from 'bun:test';
import {
  ClinamenTier,
  getClinamenCost,
  getClinamenDurationMicrodays,
  calculateSothicDebtLimit,
  EGYPTIAN_IDEAL_DAYS,
  EGYPTIAN_EPAGOMENAL_DAYS,
  COPTIC_SOLAR_YEAR,
  COPTIC_LEAP_YEAR,
  PI_MICRODAYS,
  NATURAL_LUNAR_MONTH
} from './gnostic-time';

describe('Gnostic Time - Clinamen Ladder', () => {
  it('The clinamen cost is invariant (always Barbelo = 1) across all tiers', () => {
    expect(getClinamenCost(ClinamenTier.Second)).toBe(1n);
    expect(getClinamenCost(ClinamenTier.Day)).toBe(1n);
    expect(getClinamenCost(ClinamenTier.Month)).toBe(1n);
    expect(getClinamenCost(ClinamenTier.Picolorenzo)).toBe(1n);
  });

  it('The clinamen duration correctly scales based on the tier choice', () => {
    // A leap second is technically ~11 microdays (1000000 / 86400)
    expect(getClinamenDurationMicrodays(ClinamenTier.Second)).toBe(1000000n / 86400n);
    // A leap day is exactly 1 million microdays
    expect(getClinamenDurationMicrodays(ClinamenTier.Day)).toBe(1000000n);
    // A leap month is a full synodic month
    expect(getClinamenDurationMicrodays(ClinamenTier.Month)).toBe(NATURAL_LUNAR_MONTH);
    // A leap pLo is exactly Pi microdays
    expect(getClinamenDurationMicrodays(ClinamenTier.Picolorenzo)).toBe(PI_MICRODAYS);
  });

  it('The Egyptian / Coptic formal base structure is correct', () => {
    expect(EGYPTIAN_IDEAL_DAYS).toBe(360n);
    expect(EGYPTIAN_EPAGOMENAL_DAYS).toBe(5n); // 5 primitives
    expect(COPTIC_SOLAR_YEAR).toBe(365n);
    expect(COPTIC_LEAP_YEAR).toBe(366n);       // 365 + 1 day clinamen
  });

  it('Sothic debt calculates the correct maximum deferral limit', () => {
    // 360 * 4 = 1440
    expect(calculateSothicDebtLimit()).toBe(1440n); 
  });
});
